 98→void ULFPDeploymentWidget::UpdateSlotVisual(int32 Index)
 99→{
100→	UImage* Img = GetUnitImage(Index);
101→	if (!Img) return;
102→
103→	if (PlacedStates.IsValidIndex(Index) && PlacedStates[Index])
104→	{
105→		// 已放置：半透明
106→		Img->SetColorAndOpacity(FLinearColor(0.5f, 0.5f, 0.5f, 0.5f));
107→	}
108→	else
109→	{
110→		// 未放置：正常
111→		Img->SetColorAndOpacity(FLinearColor::White);
112→	}
113→}
