 460→void ALFPTacticsPlayerController::OnCameraPan(const FInputActionValue& Value)
 461→{
 462→    // 获取输入值（WASD/方向键）
 463→    const FVector2D PanValue = Value.Get<FVector2D>();
 464→
 465→    // 计算移动方向（基于当前相机旋转）
 466→    FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
 467→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
 468→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
 469→
 470→    // 计算移动偏移
 471→    FVector PanDirection = (Forward * PanValue.Y) + (Right * PanValue.X);
 472→    PanDirection.Z = 0;
 473→    PanDirection.Normalize();
 474→
 475→    // 应用移动
 476→    CameraOffset += PanDirection * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
 477→}
