1148→void ALFPTacticsPlayerController::ConfirmDeployment()
1149→{
1150→    if (!bIsInDeployment) return;
1151→
1152→    // 取消高亮
1153→    for (ALFPHexTile* Tile : PlayerSpawnTiles)
1154→    {
1155→        if (Tile)
1156→        {
1157→            Tile->SetMovementHighlight(false);
1158→        }
1159→    }
1160→    PlayerSpawnTiles.Empty();
1161→
1162→    // 移除布置 UI
1163→    if (DeploymentWidget)
1164→    {
1165→        DeploymentWidget->OnUnitSelected.RemoveDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1166→        DeploymentWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1167→        DeploymentWidget->RemoveFromParent();
1168→    }
1169→
1170→    bIsInDeployment = false;
1171→    bIsPlacingUnit = false;
1172→
1173→    // 通知 TurnManager 结束布置阶段
1174→    ALFPTurnManager* TurnManager = GetTurnManager();
1175→    if (TurnManager)
1176→    {
1177→        TurnManager->EndDeploymentPhase();
1178→    }
1179→
1180→    UE_LOG(LogTemp, Log, TEXT("布置确认，进入战斗"));
1181→}
